import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  MenuItem,
  TextField,
  CircularProgress,
  Chip,
} from '@mui/material';
import { API_URL } from '../utils/apiUrl';
import { AuthContext } from '../context/AuthContext';

export default function SalesReport() {
  const { user } = useContext(AuthContext);

  const isSuperAdmin = user?.role === 'SUPER_ADMIN' || user?.role === 'ADMIN';

  const [outlets, setOutlets] = useState([]);
  const [selectedOutlet, setSelectedOutlet] = useState(
    isSuperAdmin ? 'all' : user?.outlet_id
  );
  const [summary, setSummary] = useState(null);
  const [allSummaries, setAllSummaries] = useState([]);
  const [recentSales, setRecentSales] = useState([]);
  const [loading, setLoading] = useState(true);

  // SuperAdmin hole shob outlet fetch kora
  useEffect(() => {
    if (isSuperAdmin) {
      axios
        .get(`${API_URL}/api/outlets`)
        .then((res) => setOutlets(res.data.data || []));
    }
  }, [user]);

  // Report Fetch (selectedOutlet change holei call hobe)
  const fetchReport = async () => {
    try {
      setLoading(true);

      if (isSuperAdmin && selectedOutlet === 'all') {
        // Shob outlet er summary
        const [summaryRes, salesRes] = await Promise.all([
          axios.get(`${API_URL}/api/reports/outlets`),
          axios.get(`${API_URL}/api/sales`),
        ]);
        setAllSummaries(summaryRes.data.data || []);
        setSummary(null);
        setRecentSales((salesRes.data.data || []).slice(0, 10));
      } else {
        // Specific outlet (SuperAdmin filtered or Branch Manager)
        const outletId =
          selectedOutlet === 'all' ? user?.outlet_id : selectedOutlet;
        const [summaryRes, salesRes] = await Promise.all([
          axios.get(`${API_URL}/api/reports/outlets/${outletId}`),
          axios.get(`${API_URL}/api/sales?outlet_id=${outletId}`),
        ]);
        setSummary(summaryRes.data.data);
        setAllSummaries([]);
        setRecentSales((salesRes.data.data || []).slice(0, 10));
      }
    } catch (error) {
      console.error('Report Error:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (selectedOutlet !== undefined && selectedOutlet !== null) fetchReport();
  }, [selectedOutlet]);

  const grandTotalRevenue = allSummaries.reduce(
    (sum, s) => sum + (s.total_revenue || 0),
    0
  );
  const grandTotalSales = allSummaries.reduce(
    (sum, s) => sum + (s.total_sales_count || 0),
    0
  );

  return (
    <Box sx={{ p: 3 }}>
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          mb: 3,
        }}
      >
        <Typography variant="h4" fontWeight="bold">
          {isSuperAdmin
            ? 'HQ Global Sales Report'
            : `Sales Report - ${user?.outlet?.name}`}
        </Typography>

        {/* SuperAdmin Dropdown */}
        {isSuperAdmin && (
          <TextField
            select
            label="Filter by Outlet"
            value={selectedOutlet}
            onChange={(e) => setSelectedOutlet(e.target.value)}
            sx={{ minWidth: 200 }}
            size="small"
          >
            <MenuItem value="all">All Outlets</MenuItem>
            {outlets.map((o) => (
              <MenuItem key={o.id} value={o.id}>
                {o.name}
              </MenuItem>
            ))}
          </TextField>
        )}
      </Box>

      {loading ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', mt: 8 }}>
          <CircularProgress />
        </Box>
      ) : (
        <>
          {/* ── Single Outlet View (Branch Manager OR SuperAdmin filtered) ── */}
          {summary && (
            <>
              <Grid container spacing={3} sx={{ mb: 4 }}>
                <Grid item xs={12} md={4}>
                  <Card sx={{ bgcolor: 'success.main', color: 'white' }}>
                    <CardContent>
                      <Typography variant="h6">Total Revenue</Typography>
                      <Typography variant="h3">
                        ৳{summary.total_revenue?.toLocaleString()}
                      </Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} md={4}>
                  <Card sx={{ bgcolor: 'primary.main', color: 'white' }}>
                    <CardContent>
                      <Typography variant="h6">Total Sales</Typography>
                      <Typography variant="h3">
                        {summary.total_sales_count}
                      </Typography>
                    </CardContent>
                  </Card>
                </Grid>

                <Grid item xs={12} md={8}>
                  <Card variant="outlined">
                    <CardContent>
                      <Typography variant="h6" fontWeight="bold">
                        Top 5 Selling Items
                      </Typography>
                      <Table size="small">
                        <TableHead>
                          <TableRow>
                            <TableCell>#</TableCell>
                            <TableCell>Product</TableCell>
                            <TableCell align="right">Qty</TableCell>
                            <TableCell align="right">Revenue</TableCell>
                          </TableRow>
                        </TableHead>
                        <TableBody>
                          {summary.top_5_items.map((item, i) => (
                            <TableRow key={item.outlet_product_id} hover>
                              <TableCell>
                                <Chip
                                  label={i + 1}
                                  size="small"
                                  color={i === 0 ? 'warning' : 'default'}
                                />
                              </TableCell>
                              <TableCell>{item.product_name}</TableCell>
                              <TableCell align="right">
                                {item.total_qty_sold}
                              </TableCell>
                              <TableCell align="right">
                                ৳{item.total_revenue?.toLocaleString()}
                              </TableCell>
                            </TableRow>
                          ))}
                        </TableBody>
                      </Table>
                    </CardContent>
                  </Card>
                </Grid>
              </Grid>
            </>
          )}

          {/* ── All Outlets View (SuperAdmin only) ── */}
          {allSummaries.length > 0 && (
            <>
              <Grid container spacing={3} sx={{ mb: 4 }}>
                <Grid item xs={12} md={4}>
                  <Card sx={{ bgcolor: 'success.main', color: 'white' }}>
                    <CardContent>
                      <Typography variant="h6">Grand Total Revenue</Typography>
                      <Typography variant="h3">
                        ৳{grandTotalRevenue.toLocaleString()}
                      </Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} md={4}>
                  <Card sx={{ bgcolor: 'primary.main', color: 'white' }}>
                    <CardContent>
                      <Typography variant="h6">Total Transactions</Typography>
                      <Typography variant="h3">{grandTotalSales}</Typography>
                    </CardContent>
                  </Card>
                </Grid>
                <Grid item xs={12} md={4}>
                  <Card sx={{ bgcolor: 'secondary.main', color: 'white' }}>
                    <CardContent>
                      <Typography variant="h6">Active Outlets</Typography>
                      <Typography variant="h3">
                        {allSummaries.length}
                      </Typography>
                    </CardContent>
                  </Card>
                </Grid>
              </Grid>

              {/* Outlet Breakdown Table */}
              <Card variant="outlined" sx={{ mb: 3 }}>
                <CardContent>
                  <Typography variant="h6" fontWeight="bold" gutterBottom>
                    Outlet Breakdown
                  </Typography>
                  <Table size="small">
                    <TableHead sx={{ bgcolor: '#f5f5f5' }}>
                      <TableRow>
                        <TableCell>Outlet</TableCell>
                        <TableCell align="right">Transactions</TableCell>
                        <TableCell align="right">Revenue</TableCell>
                        <TableCell>Top Item</TableCell>
                      </TableRow>
                    </TableHead>
                    <TableBody>
                      {allSummaries.map((s) => (
                        <TableRow key={s.outlet_id} hover>
                          <TableCell>
                            <b>{s.outlet_name}</b>
                          </TableCell>
                          <TableCell align="right">
                            {s.total_sales_count}
                          </TableCell>
                          <TableCell align="right">
                            ৳{s.total_revenue?.toLocaleString()}
                          </TableCell>
                          <TableCell>
                            {s.top_5_items[0]?.product_name ?? '—'}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </CardContent>
              </Card>
            </>
          )}

          {/* Recent Sales (dono role er jonno) */}
          <Card variant="outlined">
            <CardContent>
              <Typography variant="h6" fontWeight="bold" gutterBottom>
                Recent Sales
              </Typography>
              <Table>
                <TableHead sx={{ bgcolor: '#f5f5f5' }}>
                  <TableRow>
                    <TableCell>Receipt</TableCell>
                    {isSuperAdmin && <TableCell>Outlet</TableCell>}
                    <TableCell>Customer</TableCell>
                    <TableCell align="right">Amount</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {recentSales.length === 0 ? (
                    <TableRow>
                      <TableCell
                        colSpan={isSuperAdmin ? 4 : 3}
                        align="center"
                        sx={{ color: 'text.secondary' }}
                      >
                        No sales found
                      </TableCell>
                    </TableRow>
                  ) : (
                    recentSales.map((sale) => (
                      <TableRow key={sale.id} hover>
                        <TableCell>
                          <b>{sale.receipt_no}</b>
                        </TableCell>
                        {isSuperAdmin && (
                          <TableCell>{sale.outlet?.name ?? '—'}</TableCell>
                        )}
                        <TableCell>{sale.customer?.name || 'Guest'}</TableCell>
                        <TableCell align="right">
                          ৳{sale.total_amount?.toLocaleString()}
                        </TableCell>
                      </TableRow>
                    ))
                  )}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </>
      )}
    </Box>
  );
}
